const data = $input.first().json;

// INPUT credit charges (include LLM cost)
const inputCreditMap = {
  text:    15,
  audio:   27,   // voice note input
  image:   18,   // image input
  file:    18,   // file/PDF input
  video:    0,   // video input blocked at the source
  unknown: 15,   // fallback
};

const msgType = data.message_type_in || 'text';
const inputCredits = inputCreditMap[msgType] ?? 15;

return { json: {
  conversation_id: data.conversation_id,
  tenant_id:       data.tenant_id,
  chat_id:         data.chat_id,
  bot_token:       data.bot_token,
  user_message:    data.user_message,
  agent_reply:     data.agent_reply,
  response_type:   data.response_type,
  message_type_in: msgType,
  is_owner:        data.is_owner || false,
  tokens_used:     0,
  credits_charged: inputCredits,
  wa_instance: data.wa_instance || '',
}};

const items = $input.all();

return items.map(item => {
  const binaryData = item.binary;
  const binaryKey = Object.keys(binaryData || {})[0]; // Get whatever key exists

  if (binaryData && binaryKey) {
    const newBinaryData = { ...binaryData[binaryKey] };
    newBinaryData.fileName = (newBinaryData.fileName || 'audio.ogg').replace('.oga', '.ogg');
    newBinaryData.fileExtension = 'ogg';
    newBinaryData.mimeType = 'audio/ogg';

    return {
      json: item.json,
      binary: {
        data: newBinaryData
      }
    };
  }

  return item;
});

const transcriptionText = $json.text || '';

return {
  json: {
    message: {
      text: transcriptionText
    }
  }
};

const groqResponse = $input.first().json;
const content = groqResponse.choices?.[0]?.message?.content;

if (!content) {
  throw new Error('No content in Groq vision response: ' + JSON.stringify(groqResponse));
}

let extractedData;
try {
  extractedData = JSON.parse(content);
} catch {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    try { extractedData = JSON.parse(match[0]); }
    catch { throw new Error('Could not parse vision response: ' + content); }
  } else {
    throw new Error('Could not parse vision response: ' + content);
  }
}

const accounts = extractedData.accounts || [];
accounts.forEach(account => {
  if (account.account_number) {
    const cleaned = String(account.account_number).replace(/\D/g, '');
    account.account_number_cleaned = cleaned;
    account.is_valid = cleaned.length === 10;
  }
});

const isFinancial       = extractedData.is_financial === true;
const isProductRef      = extractedData.is_product_reference === true;
const imageTypeHint     = extractedData.image_type_hint || 'other';
const suggestedName     = extractedData.suggested_name || null;
const suggestedCategory = extractedData.suggested_category || null;
const productSpecs      = extractedData.product_specs || {};
const imageDescription  = extractedData.image_description || '';
const caption           = $('Parse WhatsApp Update').first().json.caption || '';
const isOwner           = false; // WA handler is customer-only

let contextText;

if (isFinancial) {
  contextText = accounts.length > 0
    ? `User sent a financial image. Extracted accounts: ${JSON.stringify(accounts)}. Type: ${extractedData.financial_type}. Context: ${extractedData.suggested_response_context || ''}`
    : `User sent a financial image (${extractedData.financial_type}) but no accounts extracted. Description: ${imageDescription}`;
} else if (isProductRef) {
  const specsStr = Object.entries(productSpecs)
    .filter(([,v]) => v)
    .map(([k,v]) => `${k}: ${v}`)
    .join(', ');
  contextText = `Customer sent a product reference image. Description: ${imageDescription}.`
    + (specsStr ? ` Visible specs: ${specsStr}.` : '')
    + (caption ? ` They wrote: ${caption}.` : '')
    + ` [is_product_reference: true]`;
} else {
  contextText = `User sent an image. Description: ${imageDescription}.${caption ? ' Caption: ' + caption : ''}`;
}

return [{
  json: {
    is_financial:               isFinancial,
    financial_type:             extractedData.financial_type || 'none',
    extractedamount:            extractedData.amount_transferred || null,
    accounts,
    count:                      accounts.length,
    text:                       contextText,
    image_description:          imageDescription,
    suggested_response_context: extractedData.suggested_response_context || '',
    caption,
    image_type_hint:            imageTypeHint,
    suggested_name:             suggestedName,
    suggested_category:         suggestedCategory,
    is_product_reference:       isProductRef,
    product_specs:              productSpecs,
    is_owner:                   false
  }
}];

const update  = $('Parse WhatsApp Update').first().json;
const ownerID = $('Fetch Owner ID').first().json;

let text         = update.text || '';
let message_type = update.message_type;
let image_description = null;
let is_financial = false;
let source_image_url = null;

// Audio path
try {
  const audioText = $('Format Audio to Text').first().json.message?.text;
  if (audioText) { text = audioText; message_type = 'audio'; }
} catch(e) {}

// Image path
try {
  const vision = $('Format Vision Output').first().json;
  if (vision && vision.text) {
    text = vision.text;
    message_type = 'image';
    image_description = vision.image_description || null;
    is_financial = vision.is_financial || false;
  }
  const prepVision = $('Prepare Vision Request').first().json;
  if (prepVision._image_url) source_image_url = prepVision._image_url;
} catch(e) {}

// File path
try {
  const fileOut = $('Format File Output').first().json;
  if (fileOut && fileOut.text) { text = fileOut.text; message_type = 'file'; }
} catch(e) {}

if (!text && update.caption) text = update.caption;

return { json: {
  bot_token:        ownerID.bot_token || '',
  wa_instance:      update.wa_instance || '',
  tenant_id:        $('Inject Tenant ID').first().json.tenant_id,
  business_id:      ownerID.business_id,
  chat_id:          update.chat_id,
  sender_id:        update.sender_id,
  first_name:       update.first_name,
  text,
  caption:          update.caption,
  message_type,
  image_description,
  is_financial,
  is_start:         update.is_start,
  voice_file_id:    update.voice_file_id,
  photo_file_id:    update.photo_file_id,
  source_image_url,
  platform:         'whatsapp'
}};

