const data = $input.first().json;
const msgType = $('Parse WhatsApp Update').first().json.message_type;
const isOwner = String($('Fetch Owner ID').first().json.telegram_id) === 
                String($('Parse WhatsApp Update').first().json.sender_id);

let allowed = true;
let reason = '';

if (isOwner) {
  // Owners have no limits
  allowed = true;
} else {
  if (msgType === 'text') {
    allowed = data.text_allowed === true || data.text_allowed === 'true';
    reason = allowed ? '' : 'text_hourly_limit';
  } else if (msgType === 'image') {
    allowed = data.image_allowed === true || data.image_allowed === 'true';
    reason = allowed ? '' : 'image_daily_limit';
  } else if (msgType === 'audio') {
    allowed = data.voice_allowed === true || data.voice_allowed === 'true';
    reason = allowed ? '' : 'voice_daily_limit';
  } else if (msgType === 'file') {
    allowed = data.file_allowed === true || data.file_allowed === 'true';
    reason = allowed ? '' : 'file_daily_limit';
  }
}

return { json: { allowed, reason, msgType } };

const response = $input.item.json;
const update = $('Parse WhatsApp Update').first().json;

// ── Path A: Pre-processed text (from table_7 File Text — XLSX, CSV, TXT)
// These arrive with { text, file_type, file_name } already structured
const isPreProcessed = response?.text && response?.file_type && !response?.choices;

if (isPreProcessed) {
  const fileName = response.file_name || update.file_name || 'file';
  const caption = update.caption || '';
  const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

  const MAX_CHARS = 15000;
  const raw = response.text || '';
  const truncated = raw.length > MAX_CHARS;
  const finalText = truncated
    ? raw.slice(0, MAX_CHARS) + '\n\n[Document truncated — this is a large file. Only the first portion is shown. If you need specific information not visible here, ask the user to describe it.]'
    : raw;

  return [{
    json: {
      text: finalText + captionNote,
      message_type: 'file',
      file_type: response.file_type || 'unknown',
      is_financial: false,
      file_summary: raw.slice(0, 500) || ''
    }
  }];
}

// ── Path B: Groq API response (from table_8 Processing Agent — PDF, DOCX, images)
const rawOutput = response?.choices?.[0]?.message?.content || '';

let parsed;
try {
  parsed = JSON.parse(rawOutput);
} catch {
  const match = rawOutput.match(/\{[\s\S]*\}/);
  try {
    parsed = match ? JSON.parse(match[0]) : null;
  } catch {
    parsed = null;
  }
}

// If JSON parsing fails entirely, preserve whatever Groq returned as plain text
if (!parsed) {
  parsed = {
    file_type: 'unknown',
    is_financial: false,
    full_text: rawOutput || 'Could not read file content.',
    financial_details: {},
    key_entities: [],
    document_title: null
  };
}

const fileName = update.file_name || 'file';
const caption = update.caption || '';
const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

let contextText = '';

if (parsed.is_financial) {
  // Financial documents — all structured details surfaced first, then full text
  const fd = parsed.financial_details || {};
  const financialBlock = [
    fd.transaction_refs?.length ? 'Transaction references: ' + fd.transaction_refs.join(', ') : '',
    fd.amounts?.length          ? 'Amounts: '               + fd.amounts.join(', ')           : '',
    fd.account_numbers?.length  ? 'Account numbers: '       + fd.account_numbers.join(', ')   : '',
    fd.bank_names?.length       ? 'Banks: '                 + fd.bank_names.join(', ')         : '',
    fd.dates?.length            ? 'Dates: '                 + fd.dates.join(', ')              : '',
    fd.payer  ? 'Payer: '  + fd.payer  : '',
    fd.payee  ? 'Payee: '  + fd.payee  : '',
    fd.status ? 'Status: ' + fd.status : ''
  ].filter(Boolean).join('\n');

  contextText =
    'File: ' + fileName + '\n' +
    'Type: ' + (parsed.file_type || 'financial document').toUpperCase() + '\n' +
    (parsed.document_title ? 'Title: ' + parsed.document_title + '\n' : '') +
    '\n=== FINANCIAL DETAILS ===\n' +
    financialBlock +
    '\n\n=== FULL DOCUMENT CONTENT ===\n' +
    (parsed.full_text || '') +
    (parsed.key_entities?.length ? '\n\nKey entities: ' + parsed.key_entities.join(', ') : '');

} else {
  // Non-financial documents
  contextText =
    'File: ' + fileName + '\n' +
    'Type: ' + (parsed.file_type || 'document').toUpperCase() + '\n' +
    (parsed.document_title ? 'Title: ' + parsed.document_title + '\n' : '') +
    '\n=== DOCUMENT CONTENT ===\n' +
    (parsed.full_text || '') +
    (parsed.key_entities?.length ? '\n\nKey entities: ' + parsed.key_entities.join(', ') : '');
}

// Cap at 15,000 chars (~3,750 tokens) — leaves room for system prompt + agent response
const MAX_CHARS = 15000;
const truncated = contextText.length > MAX_CHARS;
const finalText = truncated
  ? contextText.slice(0, MAX_CHARS) + '\n\n[Document truncated — this is a large file. Only the first portion is shown. If you need specific information not visible here, ask the user to describe it.]'
  : contextText;

return [{
  json: {
    text: finalText + captionNote,
    message_type: 'file',
    file_type: parsed.file_type || 'unknown',
    is_financial: parsed.is_financial || false,
    file_summary: (parsed.full_text || '').slice(0, 500)  // short preview for logging only
  }
}];

const update = $('Parse WhatsApp Update').first().json;
const fileName = update.file_name || 'file';
const fileMime = update.file_mime || '';
const caption = update.caption || '';

let extractedText = '';
let fileType = 'unknown';

// Determine file type from table_12
if (fileMime.includes('wordprocessing')) fileType = 'docx';
else if (fileMime.includes('spreadsheet') || fileMime.includes('excel')) fileType = 'xlsx';
else if (fileMime === 'text/csv') fileType = 'csv';
else if (fileMime === 'text/plain') fileType = 'txt';

// Try spreadsheet/table data (XLSX, CSV) — preserve ALL rows, not capped
try {
  const rows = $input.first().json;
  if (Array.isArray(rows) && rows.length > 0) {
    const headers = Object.keys(rows[0]).join(' | ');
    const dataRows = rows.map(row =>
      Object.values(row).map(v => String(v ?? '')).join(' | ')
    ).join('\n');
    extractedText = 'File: ' + fileName + '\nType: ' + fileType.toUpperCase() + '\n\n' +
                    'Headers: ' + headers + '\n\n' +
                    'Data (' + rows.length + ' rows):\n' + dataRows;
  }
} catch(e) {}

// Try plain text / DOCX output — full content
if (!extractedText) {
  try {
    const raw = $input.first().json.text || $input.first().json.data || '';
    extractedText = 'File: ' + fileName + '\nType: ' + fileType.toUpperCase() + '\n\n' +
                    'Full content:\n' + raw;
  } catch(e) {}
}

if (!extractedText) {
  extractedText = 'File: ' + fileName + ' — could not extract text content.';
}

// Cap at ~12,000 chars to stay within context limits
// This is roughly 3,000 tokens — leaves room for system prompt + agent response
const MAX_CHARS = 12000;
const truncated = extractedText.length > MAX_CHARS;
const finalText = truncated 
  ? extractedText.slice(0, MAX_CHARS) + '\n\n[Content truncated — document is large]'
  : extractedText;

const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

return [{ json: {
  // This is what goes to Normalise Input as the full user context
  text: finalText + captionNote,
  message_type: 'file',
  file_type: fileType,
  file_name: fileName,
  is_financial: false,  // will be overridden if PDF path detects it
  file_summary: ''       // no summary — full content passed directly
}}];

