const waResponse = $('Download WhatsApp').first().json;
const base64 = waResponse.base64 || '';
const mimetype = waResponse.mimetype || 'image/jpeg';
const imageUrl = `data:${mimetype};base64,${base64}`;
const caption = $('Parse WhatsApp Update').first().json.caption || '';
const captionNote = caption ? `The sender wrote: "${caption}". ` : '';

const promptText = `Analyze this image carefully. ${captionNote}
Return ONLY a valid JSON object with exactly these fields:

{
  "is_financial": boolean,
  "financial_type": "account_details" | "receipt" | "transfer_screenshot" | "balance_screenshot" | "none",
  "accounts": [{"account_number": "string", "bank_name": "string", "account_holder_name": "string or null"}],
  "amount_transferred": "naira string or null",
  "image_description": "one clear sentence describing what is in the image",
  "suggested_name": "if this is a product/item, what a seller would call it. null if not a product.",
  "suggested_category": "single lowercase word for product category. null if not a product.",
  "image_type_hint": "logo" | "product" | "portfolio" | "other",
  "is_product_reference": boolean,
  "product_specs": {"colour": "string or null", "style": "string or null", "material": "string or null", "occasion": "string or null"}
}

RULES:
is_financial = true ONLY for bank account numbers, receipts, transfer screenshots, balance screenshots.
Nigerian banks: Access Bank, Zenith Bank, GTBank, First Bank, UBA, Sterling Bank, Ecobank, Fidelity Bank, FCMB, Stanbic IBTC, Union Bank, Keystone Bank, Polaris Bank, Wema Bank, Kuda Bank, Opay, Palmpay, Moniepoint.
is_product_reference = true if this looks like a product photo a customer might want to order.
product_specs: extract only what is clearly visible. Set fields to null if not visible.
Return ONLY the JSON. No markdown, no explanation.`;

return {
  json: {
    model: 'meta-llama/llama-4-scout-17b-16e-instruct',
    messages: [{
      role: 'user',
      content: [
        { type: 'text', text: promptText },
        { type: 'image_url', image_url: { url: imageUrl } }
      ]
    }],
    temperature: 0.1,
    max_tokens: 1024,
    _image_url: imageUrl,
    _is_owner: false
  }
};

const body = $json.body || $json;
const data = body.data || {};
const key  = data.key  || {};

// ── Event filter: only process incoming messages
if (body.event !== 'messages.upsert') return [];

// ── Ignore bot's own messages
if (key.fromMe) return [];

// ── Ignore status broadcasts
if (key.remoteJid === 'status@broadcast') return [];

// ── Ignore group messages
if (key.remoteJid?.endsWith('@g.us')) return [];

// ── Ignore newsletter channels
if (key.remoteJid?.endsWith('@newsletter')) return [];

// ── Ignore sticker-only messages
const msg = data.message || {};
if (msg.stickerMessage && !msg.conversation && !msg.extendedTextMessage) return [];

// ── Resolve instance → business_id (Resolve Tenant node fills tenant_id)
const instanceName = body.instance || '';
const business_id  = $json.query?.businessId || instanceName.replace(/^msq_/, '');
const tenant_id    = $json.query?.tenantId   || '';

if (!business_id) throw new Error('Cannot determine business_id — check instance name format: msq_{business_id}');

const chat_id    = key.remoteJid;
const sender_id  = key.remoteJid;
const first_name = data.pushName || '';
const username   = '';

const text =
  msg.conversation                      ||
  msg.extendedTextMessage?.text         ||
  msg.imageMessage?.caption             ||
  msg.videoMessage?.caption             ||
  msg.documentMessage?.caption          ||
  '';

const caption = msg.imageMessage?.caption || msg.videoMessage?.caption || '';

const message_type =
  msg.audioMessage    ? 'audio'   :
  msg.imageMessage    ? 'image'   :
  msg.videoMessage    ? 'video'   :
  msg.documentMessage ? 'file'    :
  msg.stickerMessage  ? 'sticker' :
  (msg.conversation || msg.extendedTextMessage) ? 'text' : 'unknown';

const voice_file_id = msg.audioMessage    ? key.id : null;
const photo_file_id = msg.imageMessage    ? key.id : null;
const file_id       = msg.documentMessage ? key.id : null;
const video_file_id = msg.videoMessage    ? key.id : null;

const wa_instance = instanceName || `msq_${business_id}`;

return { json: {
  // Identity — filled in by Resolve Tenant / Inject Tenant ID
  tenant_id,
  business_id,
  wa_instance,

  // Sender
  chat_id,
  sender_id,
  first_name,
  username,

  // Message content
  text,
  caption,
  message_id: key.id,
