const ctx       = $('Fetch Start Context').first().json;
const bizName   = ctx.business_name  || 'us';
const agentName = ctx.agent_name     || 'your assistant';
const mode      = (ctx.business_mode || 'product_only').trim();
const rawDesc   = (ctx.business_description || '').trim();

const isService = mode === 'service_only';
const isHybrid  = mode === 'hybrid_product_led' || mode === 'hybrid_service_led';

let descLine = '';
if (rawDesc) {
  let sentence = rawDesc.split(/[.!?\n]/)[0].trim();
  if (sentence.length > 130) sentence = sentence.substring(0, 127) + '...';
  sentence = sentence.replace(/^I\b/i, 'We');
  descLine = sentence + '.';
}

const invite = isService
  ? 'Got questions or want to book? Just say the word 👇'
  : isHybrid
  ? 'Want to see what we offer, place an order, or just ask a question? Go ahead 👇'
  : 'Want to see what we have, ask about pricing, or place an order? Just tell us 👇';

let msg = '👋 *Welcome to ' + bizName + '!*\n\n';
if (descLine) msg += descLine + '\n\n';
msg += agentName + ' is here to help you — day or night. 🌟\n\n';
msg += invite;

return [{ json: { welcome_text: msg } }];

